package main

import (
	"html/template"
	"net/http"
)

type Comment struct {
	Text string
}

func handler(w http.ResponseWriter, r *http.Request) {
	comments := []Comment{
		{Text: "This is a <strong>great</strong> comment!"},
		{Text: "<em>Nice</em> to meet you."},
		{Text: "Check out this <a href='https://example.com'>link</a>.<p>And here's some new line.</p>"},
	}

	tmpl := template.Must(template.New("comments").Parse(`
	<html>
	<head><title>User Comments</title></head>
	<body>
	<h1>User Comments</h1>
	<ul>
	{{range .}}
	<li>{{.Text}}</li>
	{{end}}
	</ul>
	</body>
	</html>
	`))

	err := tmpl.Execute(w, comments)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
	}
}

func main() {
	http.HandleFunc("/", handler)
	http.ListenAndServe(":8080", nil)
}